const WebSocket = require('ws');
const wss = new WebSocket.Server({ port: 8080 });

let players = {};
let units = {};

wss.on('connection', (ws) => {
    console.log('Client connected');

    ws.on('message', (message) => {
        const data = JSON.parse(message);
        const playerID = data.playerID;

        if (!players[playerID]) {
            players[playerID] = { units: [] };
        }

        switch (data.command) {
            case 'build':
                buildUnit(playerID, data.unitType);
                break;
            case 'attack':
                attackUnit(playerID, data.targetPlayerID, data.unitIndex);
                break;
            case 'move':
                moveUnit(playerID, data.unitIndex, data.x, data.y);
                break;
        }
    });

    ws.on('close', () => {
        console.log('Client disconnected');
    });
});

function buildUnit(playerID, unitType) {
    const player = players[playerID];
    const newUnit = { type: unitType, x: 0, y: 0 };
    player.units.push(newUnit);
}

function attackUnit(playerID, targetPlayerID, unitIndex) {
    const player = players[playerID];
    const targetPlayer = players[targetPlayerID];

    if (targetPlayer && player.units[unitIndex]) {
        // Simulate attack logic here
        console.log(`Player ${playerID} attacks Player ${targetPlayerID}`);
    }
}

function moveUnit(playerID, unitIndex, x, y) {
    const player = players[playerID];
    if (player.units[unitIndex]) {
        player.units[unitIndex].x = x;
        player.units[unitIndex].y = y;
    }
}